def threeway(base, theirs, ours):
    """Return (merged_lines, conflict_bool). Clean iff base->ours changed ranges
    don't overlap base->theirs changed ranges."""
    b=base.splitlines(keepends=True); o=theirs.splitlines(keepends=True); a=ours.splitlines(keepends=True)
    # changed base-index ranges on each side
    def changed_ranges(x):
        r=[]
        for tag,i1,i2,j1,j2 in difflib.SequenceMatcher(None,b,x,autojunk=False).get_opcodes():
            if tag!='equal': r.append((i1,i2,tag,j1,j2,x))
        return r
    theirs_ch=changed_ranges(o); ours_ch=changed_ranges(a)
    # overlap check on base coordinates
    for (i1,i2,*_) in theirs_ch:
        for (k1,k2,*_) in ours_ch:
            if max(i1,k1) < min(i2,k2) or (i1==i2 and k1==k2==i1) :  # overlapping or same insertion point
                if not (i2<=k1 or k2<=i1):
                    return None, True
    # build merged: walk base, apply theirs and ours substitutions by base position
    subs={}  # base_start -> (base_end, replacement_lines)
    for (i1,i2,tag,j1,j2,src) in theirs_ch: subs[i1]=(i2, src.splitlines(keepends=True)[j1:j2])
    for (i1,i2,tag,j1,j2,src) in ours_ch:   subs[i1]=(i2, src.splitlines(keepends=True)[j1:j2])
    out=[]; idx=0
    for start in sorted(subs):
        if start<idx:  # overlap slipped through
            return None, True
        out.extend(b[idx:start]); end,repl=subs[start]; out.extend(repl); idx=end
    out.extend(b[idx:])
    return "".join(out), False

