def grab(txt, needle, ctx=0):
    lines=txt.splitlines()
    for i,l in enumerate(lines):
        if needle in l: 
            return "\n".join(lines[max(0,i-ctx):i+ctx+1])
    return f"<'{needle}' not found>"

