import time
def api(path, method="GET", body=None, _tries=4):
    data=json.dumps(body).encode() if body is not None else None
    for i in range(_tries):
        req=urllib.request.Request(f"{API}{path}", data=data, method=method,
            headers={"Authorization":f"token {tok}","Accept":"application/vnd.github+json",
                     "Content-Type":"application/json","User-Agent":"science-agent"})
        try:
            with urllib.request.urlopen(req,timeout=40) as r:
                raw=r.read().decode(); return r.status,(json.loads(raw) if raw else {})
        except urllib.error.HTTPError as e:
            raw=e.read().decode() if e.fp else ""
            if e.code in (502,503,504) and i<_tries-1: time.sleep(3*(i+1)); continue
            try: return e.code,(json.loads(raw) if raw else {})
            except: return e.code,{"_raw":raw[:200]}
        except urllib.error.URLError as e:
            if i<_tries-1: time.sleep(3*(i+1)); continue
            raise
